            "N" | "M" | "NM" | "ROWS" | "COLUMNS" | "START" | "END" | "START_0BASED"
            | "END_0BASED" | "START_1BASED" | "END_1BASED" | "FEATURE_ID" | "CUT_POS_1BASED"
            | "RESIDUE_START" | "RESIDUE_END" | "LENGTH_BP" | "LEFT_END_0BASED"
