            | "FAMILY" | "ALIAS" | "CHR" | "PREFIX" | "ROUTINE_ID" | "SUGGESTION_ID"
            | "GROUP_ID" | "GUIDE_SET_ID" | "OLIGO_SET_ID" | "TEMPLATE_ID" | "MOTIF"
