    let err = parse_shell_line("/grep TP73 *.fa").expect_err("unknown slash command should fail");
    assert!(err.contains("gentle.shell_alias_rejection.v1"));
    assert!(err.contains("supported_alternatives"));
    assert!(err.contains("/list"));
