#[test]
fn parse_primers_seed_from_feature_and_splicing() {
    let feature =
        parse_shell_line("primers seed-from-feature seq_a 7").expect("parse seed-from-feature");
    assert!(matches!(
        feature,
        ShellCommand::PrimersSeedFromFeature {
            seq_id,
            feature_id
        } if seq_id == "seq_a" && feature_id == 7
    ));

    let splicing =
        parse_shell_line("primers seed-from-splicing seq_a 11").expect("parse seed-from-splicing");
    assert!(matches!(
        splicing,
        ShellCommand::PrimersSeedFromSplicing {
            seq_id,
            feature_id
        } if seq_id == "seq_a" && feature_id == 11
    ));

    let qpcr_feature = parse_shell_line("primers seed-qpcr-from-feature seq_a 13")
        .expect("parse seed-qpcr-from-feature");
    assert!(matches!(
        qpcr_feature,
        ShellCommand::PrimersSeedQpcrFromFeature {
            seq_id,
            feature_id
        } if seq_id == "seq_a" && feature_id == 13
    ));

    let qpcr_splicing = parse_shell_line("primers seed-qpcr-from-splicing seq_a 17")
        .expect("parse seed-qpcr-from-splicing");
    assert!(matches!(
        qpcr_splicing,
        ShellCommand::PrimersSeedQpcrFromSplicing {
            seq_id,
            feature_id,
            mode,
            transcript_id,
            specificity_evidence,
        } if seq_id == "seq_a"
            && feature_id == 17
            && mode == QpcrTranscriptTargetingMode::SharedGene
            && transcript_id.is_none()
            && specificity_evidence.is_none()
    ));

    let qpcr_splicing_distinguish = parse_shell_line(
        "primers seed-qpcr-from-splicing seq_a 17 --mode distinguish_transcript --transcript-id NR_187362.1 --specificity-evidence unique_exon_or_chain",
    )
    .expect("parse distinguishing seed-qpcr-from-splicing");
    assert!(matches!(
        qpcr_splicing_distinguish,
        ShellCommand::PrimersSeedQpcrFromSplicing {
            seq_id,
            feature_id,
            mode,
            transcript_id,
            specificity_evidence,
        } if seq_id == "seq_a"
            && feature_id == 17
            && mode == QpcrTranscriptTargetingMode::DistinguishTranscript
            && transcript_id.as_deref() == Some("NR_187362.1")
            && specificity_evidence
                == Some(QpcrTranscriptSpecificityEvidence::UniqueExonOrChain)
    ));

    let panel =
        parse_shell_line("primers transcript-qpcr-panel seq_a 17 shared_qpcr_1 --path panel.json")
            .expect("parse transcript qPCR panel");
    assert!(matches!(
        panel,
        ShellCommand::PrimersTranscriptQpcrPanel {
            seq_id,
            feature_id,
            shared_qpcr_report_id,
            path,
        } if seq_id == "seq_a"
            && feature_id == 17
            && shared_qpcr_report_id == "shared_qpcr_1"
            && path.as_deref() == Some("panel.json")
    ));

    let ordered_cdna = parse_shell_line(
        "primers test-cdna-pcr seq_a 17 --forward AAACCC --reverse CCCAAG --transcript-order antisense_first_exon --map-coordinate-mode genomic_aligned --svg ordered.svg --materialize-products --product-output-prefix cdna_products --product-gel-svg products.gel.svg --product-gel-ladder \"NEB 100bp DNA Ladder\"",
    )
    .expect("parse ordered cDNA PCR test");
    assert!(matches!(
        ordered_cdna,
        ShellCommand::PrimersTestCdnaPcr {
            seq_id,
            feature_id,
            transcript_order,
            transcript_map_coordinate_mode,
            svg_path,
            materialize_products,
            product_output_prefix,
            product_gel_svg_path,
            product_gel_ladders,
            ..
        } if seq_id == "seq_a"
            && feature_id == 17
            && transcript_order == Some(CdnaAssayTranscriptOrder::AntisenseFirstExon)
            && transcript_map_coordinate_mode
                == Some(CdnaAssayTranscriptMapCoordinateMode::GenomicAligned)
            && svg_path.as_deref() == Some("ordered.svg")
            && materialize_products
            && product_output_prefix.as_deref() == Some("cdna_products")
            && product_gel_svg_path.as_deref() == Some("products.gel.svg")
            && product_gel_ladders == Some(vec!["NEB 100bp DNA Ladder".to_string()])
    ));

    let fasta_order_err = parse_shell_line(
        "primers test-cdna-qpcr-fasta cdna.fa.gz --forward AAACCC --reverse CCCAAG --probe GGGCCC --transcript-order genomic_first_exon",
    )
    .expect_err("reject transcript order for cDNA FASTA screens");
    assert!(fasta_order_err.contains("only supported for transcript-derived"));
}

