fn assert_execute_genomes_status_reports_running_lifecycle_and_suppresses_prepare_hint() {
    let td = tempdir().expect("tempdir");
    let fasta = td.path().join("toy.fa");
    let gtf = td.path().join("toy.gtf");
    let cache = td.path().join("cache");
    fs::write(&fasta, ">chr1\nACGT\n").expect("write fasta");
    fs::write(
        &gtf,
        "chr1\tsrc\tgene\t1\t4\t.\t+\t.\tgene_id \"GENE1\"; gene_name \"GENE1\";\n",
    )
    .expect("write gtf");
    let catalog = td.path().join("catalog.json");
    fs::write(
        &catalog,
        format!(
            r#"{{
  "ToyGenome": {{
    "sequence_local": "{}",
    "annotations_local": "{}",
    "cache_dir": "{}"
  }}
}}"#,
            fasta.display(),
            gtf.display(),
            cache.display()
        ),
    )
    .expect("write catalog");
    let install_dir = cache.join("toygenome");
    fs::create_dir_all(&install_dir).expect("install dir");
    let status_path = install_dir.join(".prepare_activity.json");
    let lock_path = install_dir.join(".prepare_activity.lock");
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .expect("now")
        .as_millis();
    let activity = serde_json::json!({
        "genome_id": "ToyGenome",
        "status_path": status_path.display().to_string(),
        "lock_path": lock_path.display().to_string(),
        "lifecycle_status": "running",
        "prepare_mode": "prepare_or_reuse",
        "phase": "download_sequence",
        "item": "toy.fa",
        "bytes_done": 10,
        "bytes_total": 100,
        "percent": 10.0,
        "step_id": null,
        "step_label": null,
        "started_at_unix_ms": now.saturating_sub(10),
        "updated_at_unix_ms": now,
        "finished_at_unix_ms": null,
        "last_error": null,
        "owner_pid": std::process::id()
    });
    fs::write(
        &status_path,
        serde_json::to_string_pretty(&activity).expect("serialize activity"),
    )
    .expect("status");
    fs::write(
        &lock_path,
        serde_json::to_string_pretty(&activity).expect("serialize activity lock"),
    )
    .expect("lock");

    let mut engine = GentleEngine::new();
    let out = execute_shell_command(
        &mut engine,
        &ShellCommand::ReferenceStatus {
            helper_mode: false,
            genome_id: "ToyGenome".to_string(),
            catalog_path: Some(catalog.to_string_lossy().to_string()),
            cache_dir: None,
        },
    )
    .expect("execute status");

    assert_eq!(out.output["lifecycle_status"].as_str(), Some("running"));
    assert_eq!(
        out.output["current_activity"]["phase"].as_str(),
        Some("download_sequence")
    );
    assert!(out.output["prepare_command"].is_null());
    assert!(
        out.output["status_message"]
            .as_str()
            .is_some_and(|value| value.contains("already being prepared"))
    );
}

#[test]
fn execute_genomes_prepare_running_message_reports_effective_activity_path() {
    let td = tempdir().expect("tempdir");
    let root = td.path();
    let assets_dir = root.join("assets");
    fs::create_dir_all(&assets_dir).expect("create assets dir");
    let fasta = root.join("toy.fa");
    let gtf = root.join("toy.gtf");
    fs::write(&fasta, ">chr1\nACGT\n").expect("write fasta");
    fs::write(
        &gtf,
        "chr1\tsrc\tgene\t1\t4\t.\t+\t.\tgene_id \"GENE1\"; gene_name \"GENE1\";\n",
    )
    .expect("write gtf");
    let catalog = assets_dir.join("genomes.json");
    fs::write(
        &catalog,
        format!(
            r#"{{
  "ToyGenome": {{
    "sequence_local": "{}",
    "annotations_local": "{}",
    "cache_dir": "data/genomes"
  }}
}}"#,
            fasta.display(),
            gtf.display()
        ),
    )
    .expect("write catalog");

    let effective_install_dir = assets_dir.join("data/genomes/toygenome");
    fs::create_dir_all(&effective_install_dir).expect("create effective install dir");
    let status_path = effective_install_dir.join(".prepare_activity.json");
    let lock_path = effective_install_dir.join(".prepare_activity.lock");
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .expect("system time")
        .as_millis();
    let activity = serde_json::json!({
        "genome_id": "ToyGenome",
        "status_path": status_path.display().to_string(),
        "lock_path": lock_path.display().to_string(),
        "lifecycle_status": "running",
        "prepare_mode": "prepare_or_reuse",
        "phase": "index_fasta",
        "item": "sequence.fa.fai",
        "bytes_done": 1,
        "bytes_total": 10,
        "percent": 10.0,
        "step_id": null,
        "step_label": null,
        "started_at_unix_ms": now.saturating_sub(1_000),
        "updated_at_unix_ms": now,
        "finished_at_unix_ms": null,
        "last_error": null,
        "owner_pid": std::process::id()
    });
    let activity_text = serde_json::to_string_pretty(&activity).expect("serialize activity");
    fs::write(&status_path, &activity_text).expect("write activity status");
    fs::write(&lock_path, &activity_text).expect("write activity lock");

    let mut engine = GentleEngine::new();
    let out = execute_shell_command(
        &mut engine,
        &ShellCommand::ReferencePrepare {
            helper_mode: false,
            genome_id: "ToyGenome".to_string(),
            catalog_path: Some(catalog.to_string_lossy().to_string()),
            cache_dir: Some("data/genomes".to_string()),
            timeout_seconds: None,
        },
    )
    .expect("execute prepare");

    let message = out.output["result"]["messages"]
        .as_array()
        .expect("messages")
        .first()
        .and_then(|value| value.as_str())
        .expect("prepare message");
    assert!(message.contains("already running"));
    assert!(message.contains(effective_install_dir.to_string_lossy().as_ref()));
    assert!(message.contains(status_path.to_string_lossy().as_ref()));
    assert!(message.contains("phase: index_fasta"));
    assert!(
        !message.contains("in 'data/genomes'"),
        "message should not present the raw relative cache arg as the running location: {message}"
    );
}

#[test]
fn parse_ui_open_and_prepared_commands() {
    let open = parse_shell_line("ui open prepared-references --genome-id \"Human GRCh38\"")
        .expect("parse ui open");
    match open {
        ShellCommand::UiIntent {
            action,
            target,
            genome_id,
            helper_mode,
            catalog_path,
            cache_dir,
            filter,
            species,
            latest,
        } => {
            assert_eq!(action, UiIntentAction::Open);
            assert_eq!(target, UiIntentTarget::PreparedReferences);
            assert_eq!(genome_id.as_deref(), Some("Human GRCh38"));
            assert!(!helper_mode);
            assert!(catalog_path.is_none());
            assert!(cache_dir.is_none());
            assert!(filter.is_none());
            assert!(species.is_none());
            assert!(!latest);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let open_latest = parse_shell_line("ui open prepared-references --species human --latest")
        .expect("parse ui open latest");
    match open_latest {
        ShellCommand::UiIntent {
            action,
            target,
            genome_id,
            helper_mode,
            species,
            latest,
            ..
        } => {
            assert_eq!(action, UiIntentAction::Open);
            assert_eq!(target, UiIntentTarget::PreparedReferences);
            assert!(genome_id.is_none());
            assert!(!helper_mode);
            assert_eq!(species.as_deref(), Some("human"));
            assert!(latest);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let open_pcr = parse_shell_line("ui open pcr-design").expect("parse ui open pcr-design");
    match open_pcr {
        ShellCommand::UiIntent { action, target, .. } => {
            assert_eq!(action, UiIntentAction::Open);
            assert_eq!(target, UiIntentTarget::PcrDesign);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let focus_pcr = parse_shell_line("ui focus pcr-design").expect("parse ui focus pcr-design");
    match focus_pcr {
        ShellCommand::UiIntent { action, target, .. } => {
            assert_eq!(action, UiIntentAction::Focus);
            assert_eq!(target, UiIntentTarget::PcrDesign);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let close_pcr = parse_shell_line("ui close pcr-design").expect("parse ui close pcr-design");
    match close_pcr {
        ShellCommand::UiIntent { action, target, .. } => {
            assert_eq!(action, UiIntentAction::Close);
            assert_eq!(target, UiIntentTarget::PcrDesign);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let open_seq_confirm = parse_shell_line("ui open sequencing-confirmation")
        .expect("parse ui open sequencing-confirmation");
    match open_seq_confirm {
        ShellCommand::UiIntent { action, target, .. } => {
            assert_eq!(action, UiIntentAction::Open);
            assert_eq!(target, UiIntentTarget::SequencingConfirmation);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let focus_seq_confirm =
        parse_shell_line("ui focus seq-confirm").expect("parse ui focus seq-confirm");
    match focus_seq_confirm {
        ShellCommand::UiIntent { action, target, .. } => {
            assert_eq!(action, UiIntentAction::Focus);
            assert_eq!(target, UiIntentTarget::SequencingConfirmation);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    match parse_shell_line("ui close sequence-window fus_live")
        .expect("parse ui close sequence-window")
    {
        ShellCommand::UiSequenceWindow { action, seq_id } => {
            assert_eq!(action, UiIntentAction::Close);
            assert_eq!(seq_id, "fus_live");
        }
        other => panic!("unexpected command: {other:?}"),
    }

    match parse_shell_line("ui open sequence-window fus_live")
        .expect("parse ui open sequence-window")
    {
        ShellCommand::UiSequenceWindow { action, seq_id } => {
            assert_eq!(action, UiIntentAction::Open);
            assert_eq!(seq_id, "fus_live");
        }
        other => panic!("unexpected command: {other:?}"),
    }

    match parse_shell_line("ui focus sequence-window fus_live")
        .expect("parse ui focus sequence-window")
    {
        ShellCommand::UiSequenceWindow { action, seq_id } => {
            assert_eq!(action, UiIntentAction::Focus);
            assert_eq!(seq_id, "fus_live");
        }
        other => panic!("unexpected command: {other:?}"),
    }

    match parse_shell_line("ui selection sequence-window fus_live --range 10..24")
        .expect("parse ui selection sequence-window")
    {
        ShellCommand::UiSequenceSelection {
            seq_id,
            start_0based,
            end_0based_exclusive,
        } => {
            assert_eq!(seq_id, "fus_live");
            assert_eq!(start_0based, Some(10));
            assert_eq!(end_0based_exclusive, Some(24));
        }
        other => panic!("unexpected command: {other:?}"),
    }

    match parse_shell_line("ui selection sequence-window fus_live").expect("parse ui selection get")
    {
        ShellCommand::UiSequenceSelection {
            seq_id,
            start_0based,
            end_0based_exclusive,
        } => {
            assert_eq!(seq_id, "fus_live");
            assert_eq!(start_0based, None);
            assert_eq!(end_0based_exclusive, None);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let prepared = parse_shell_line("ui prepared-genomes --species human --latest")
        .expect("parse ui prepared-genomes");
    match prepared {
        ShellCommand::UiPreparedGenomes {
            helper_mode,
            species,
            latest,
            ..
        } => {
            assert!(!helper_mode);
            assert_eq!(species.as_deref(), Some("human"));
            assert!(latest);
        }
        other => panic!("unexpected command: {other:?}"),
    }

    let err = parse_shell_line("ui open agent-assistant --latest")
        .expect_err("ui open agent-assistant --latest should fail");
    assert!(
            err.contains("only supports --helpers/--catalog/--cache-dir/--filter/--species/--latest when TARGET is prepared-references"),
            "unexpected parse error: {err}"
    );
}

#[test]
fn execute_ui_intents_lists_shared_target_metadata() {
    let mut engine = GentleEngine::new();
    let out = execute_shell_command(&mut engine, &ShellCommand::UiListIntents)
        .expect("execute ui intents");

    assert!(!out.state_changed);
    assert_eq!(out.output["schema"].as_str(), Some("gentle.ui_intents.v1"));
    let targets = out.output["targets"].as_array().expect("targets array");
    let metadata = out.output["target_metadata"]
        .as_array()
        .expect("target metadata array");
    assert_eq!(targets.len(), UiIntentTarget::all().len());
    assert_eq!(metadata.len(), UiIntentTarget::all().len());

    for target in UiIntentTarget::all() {
        assert!(
            targets
                .iter()
                .any(|value| value.as_str() == Some(target.as_str())),
            "missing target string for {}",
            target.as_str()
        );
        let row = metadata
            .iter()
            .find(|value| value["target"].as_str() == Some(target.as_str()))
            .unwrap_or_else(|| panic!("missing target metadata for {}", target.as_str()));
        assert_eq!(row["title"].as_str(), Some(target.title()));
        assert_eq!(row["detail"].as_str(), Some(target.detail()));
        assert_eq!(row["keywords"].as_str(), Some(target.keywords()));
        let actions = row["actions"].as_array().expect("actions array");
        assert!(
            actions
                .iter()
                .any(|value| value.as_str() == Some(UiIntentAction::Open.as_str()))
        );
        assert!(
            actions
                .iter()
                .any(|value| value.as_str() == Some(UiIntentAction::Focus.as_str()))
        );
        if row["target"].as_str() == Some(UiIntentTarget::OpenSequence.as_str()) {
            assert!(
                !actions
                    .iter()
                    .any(|value| value.as_str() == Some(UiIntentAction::Close.as_str()))
            );
        } else {
            assert!(
                actions
                    .iter()
                    .any(|value| value.as_str() == Some(UiIntentAction::Close.as_str()))
            );
        }
    }
    assert!(
        out.output["commands"]
            .as_array()
            .expect("commands array")
            .iter()
            .any(|value| value.as_str() == Some("ui close TARGET"))
    );
    assert!(
        out.output["commands"]
            .as_array()
            .expect("commands array")
            .iter()
            .any(|value| value.as_str() == Some("ui open sequence-window SEQ_ID"))
    );
    assert!(
        out.output["commands"]
            .as_array()
            .expect("commands array")
            .iter()
            .any(|value| value.as_str() == Some("ui focus sequence-window SEQ_ID"))
    );
    assert!(
        out.output["commands"]
            .as_array()
            .expect("commands array")
            .iter()
            .any(|value| value.as_str() == Some("ui close sequence-window SEQ_ID"))
    );
    assert!(
        out.output["commands"]
            .as_array()
            .expect("commands array")
            .iter()
            .any(|value| {
                value.as_str() == Some("ui selection sequence-window SEQ_ID [--range START..END]")
            })
    );
}

