#[test]
fn execute_ui_intents_catalog_includes_target_details() {
    let mut engine = GentleEngine::new();
    let out = execute_shell_command(&mut engine, &ShellCommand::UiListIntents)
        .expect("execute ui intents catalog");
    assert!(!out.state_changed);
    let targets = out.output["targets"]
        .as_array()
        .expect("ui intents targets array");
    assert_eq!(targets.len(), UiIntentTarget::all().len());
    let target_details = out.output["target_details"]
        .as_array()
        .expect("ui intents target_details array");
    assert_eq!(target_details.len(), UiIntentTarget::all().len());
    let pcr = target_details
        .iter()
        .find(|row| row["target"].as_str() == Some("pcr-design"))
        .expect("pcr-design catalog row");
    assert_eq!(pcr["title"].as_str(), Some("PCR Designer"));
    assert_eq!(pcr["menu_path"].as_str(), Some("Patterns"));
    assert_eq!(
        pcr["optional_arguments"]
            .as_array()
            .map(|items| items.len()),
        Some(1)
    );
    let pcr_arguments = pcr["arguments"]
        .as_array()
        .expect("pcr-design arguments array");
    assert_eq!(pcr_arguments.len(), 1);
    assert_eq!(pcr_arguments[0]["name"].as_str(), Some("genome_id"));
    assert_eq!(pcr_arguments[0]["required"].as_bool(), Some(false));
    assert!(
        pcr_arguments[0]["detail"]
            .as_str()
            .is_some_and(|detail| !detail.trim().is_empty()),
        "pcr-design genome_id argument should have a detail"
    );
    let prepared = target_details
        .iter()
        .find(|row| row["target"].as_str() == Some("prepared-references"))
        .expect("prepared-references catalog row");
    assert_eq!(prepared["menu_path"].as_str(), Some("Genome"));
    assert_eq!(
        prepared["optional_arguments"]
            .as_array()
            .map(|items| items.len()),
        Some(7)
    );
    let prepared_arguments = prepared["arguments"]
        .as_array()
        .expect("prepared-references arguments array");
    assert_eq!(prepared_arguments.len(), 7);
    let prepared_argument_names: Vec<&str> = prepared_arguments
        .iter()
        .map(|argument| argument["name"].as_str().expect("argument name"))
        .collect();
    assert_eq!(
        prepared_argument_names,
        vec![
            "genome_id",
            "helpers",
            "catalog_path",
            "cache_dir",
            "filter",
            "species",
            "latest"
        ]
    );
    assert!(prepared_arguments.iter().all(|argument| {
        argument["detail"]
            .as_str()
            .is_some_and(|detail| !detail.trim().is_empty())
    }));
}

#[test]
fn execute_ui_prepared_and_latest_prepared_queries() {
    let td = tempdir().expect("tempdir");
    let fasta_113 = td.path().join("h113.fa");
    let ann_113 = td.path().join("h113.gtf");
    let fasta_116 = td.path().join("h116.fa");
    let ann_116 = td.path().join("h116.gtf");
    let cache_dir = td.path().join("cache");
    fs::write(&fasta_113, ">chr1\nACGT\n").expect("write fasta 113");
    fs::write(
        &ann_113,
        "chr1\tsrc\tgene\t1\t4\t.\t+\t.\tgene_id \"G113\"; gene_name \"G113\";\n",
    )
    .expect("write ann 113");
    fs::write(&fasta_116, ">chr1\nACGTACGT\n").expect("write fasta 116");
    fs::write(
        &ann_116,
        "chr1\tsrc\tgene\t1\t8\t.\t+\t.\tgene_id \"G116\"; gene_name \"G116\";\n",
    )
    .expect("write ann 116");
    let catalog_path = td.path().join("catalog.json");
    let catalog_json = format!(
        r#"{{
  "Human GRCh38 Ensembl 113": {{
    "sequence_local": "{}",
    "annotations_local": "{}",
    "cache_dir": "{}"
  }},
  "Human GRCh38 Ensembl 116": {{
    "sequence_local": "{}",
    "annotations_local": "{}",
    "cache_dir": "{}"
  }}
}}"#,
        fasta_113.display(),
        ann_113.display(),
        cache_dir.display(),
        fasta_116.display(),
        ann_116.display(),
        cache_dir.display()
    );
    fs::write(&catalog_path, catalog_json).expect("write catalog");

    let catalog = GenomeCatalog::from_json_file(catalog_path.to_string_lossy().as_ref()).unwrap();
    catalog
        .prepare_genome_once("Human GRCh38 Ensembl 113")
        .expect("prepare 113");
    std::thread::sleep(std::time::Duration::from_millis(2));
    catalog
        .prepare_genome_once("Human GRCh38 Ensembl 116")
        .expect("prepare 116");

    let mut engine = GentleEngine::new();
    let prepared = execute_shell_command(
        &mut engine,
        &ShellCommand::UiPreparedGenomes {
            helper_mode: false,
            catalog_path: Some(catalog_path.to_string_lossy().to_string()),
            cache_dir: None,
            filter: None,
            species: Some("human".to_string()),
            latest: false,
        },
    )
    .expect("execute ui prepared-genomes");
    assert!(!prepared.state_changed);
    assert_eq!(prepared.output["prepared_count"].as_u64(), Some(2));
    assert_eq!(
        prepared.output["genomes"][0]["genome_id"].as_str(),
        Some("Human GRCh38 Ensembl 116")
    );

    let latest = execute_shell_command(
        &mut engine,
        &ShellCommand::UiLatestPrepared {
            helper_mode: false,
            catalog_path: Some(catalog_path.to_string_lossy().to_string()),
            cache_dir: None,
            species: "human".to_string(),
        },
    )
    .expect("execute ui latest-prepared");
    assert!(!latest.state_changed);
    assert_eq!(
        latest.output["selected_genome_id"].as_str(),
        Some("Human GRCh38 Ensembl 116")
    );

    let intent_latest = execute_shell_command(
        &mut engine,
        &ShellCommand::UiIntent {
            action: UiIntentAction::Open,
            target: UiIntentTarget::PreparedReferences,
            genome_id: None,
            helper_mode: false,
            catalog_path: Some(catalog_path.to_string_lossy().to_string()),
            cache_dir: None,
            filter: None,
            species: Some("human".to_string()),
            latest: true,
        },
    )
    .expect("execute ui intent latest");
    assert!(!intent_latest.state_changed);
    assert_eq!(
        intent_latest.output["selected_genome_id"].as_str(),
        Some("Human GRCh38 Ensembl 116")
    );

    let intent_explicit = execute_shell_command(
        &mut engine,
        &ShellCommand::UiIntent {
            action: UiIntentAction::Open,
            target: UiIntentTarget::PreparedReferences,
            genome_id: Some("Human GRCh38 Ensembl 113".to_string()),
            helper_mode: false,
            catalog_path: Some(catalog_path.to_string_lossy().to_string()),
            cache_dir: None,
            filter: None,
            species: Some("human".to_string()),
            latest: true,
        },
    )
    .expect("execute ui intent explicit genome");
    assert!(!intent_explicit.state_changed);
    assert_eq!(
        intent_explicit.output["selected_genome_id"].as_str(),
        Some("Human GRCh38 Ensembl 113")
    );
    assert!(
        intent_explicit.output["prepared_query"].is_null(),
        "explicit genome_id should bypass prepared query resolution"
    );
}

