#[test]
fn execute_rna_reads_export_sample_sheet_supports_target_gene_columns() {
    let mut state = ProjectState::default();
    state
        .sequences
        .insert("seq_a".to_string(), tp53_isoform_test_sequence());
    let mut engine = GentleEngine::from_state(state);
    let feature_id = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present")
        .features()
        .iter()
        .position(|feature| feature.kind.to_string().eq_ignore_ascii_case("mRNA"))
        .expect("mRNA feature id");
    let fasta_dir = tempdir().expect("tempdir");
    let input_path = fasta_dir.path().join("reads.fa");
    fs::write(
        &input_path,
        ">read_1\nATGGAGGAGCCGCAGTCAGATCCTAGCGTCGAGCCCCCTCTGAGTCAGGAAACATTTTCAGACCTATGGAAACTACTTCCTAATGGGCCCGGATTCCTTTTCTCTGTGAACCTTCCCGATGATGATGGAGGTGGAATGGAGGAGCCGCAGTCA\n",
    )
    .expect("write input fasta");
    let mut seed_filter = RnaReadSeedFilterConfig::default();
    seed_filter.kmer_len = 3;
    seed_filter.min_seed_hit_fraction = 0.0;
    seed_filter.min_weighted_seed_hit_fraction = 0.0;
    seed_filter.min_unique_matched_kmers = 0;
    seed_filter.min_chain_consistency_fraction = 0.0;
    seed_filter.max_median_transcript_gap = 10_000.0;
    seed_filter.min_confirmed_exon_transitions = 0;
    seed_filter.min_transition_support_fraction = 0.0;
    execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsInterpret {
            seq_id: "seq_a".to_string(),
            seed_feature_id: feature_id,
            input_path: input_path.display().to_string(),
            profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
            input_format: RnaReadInputFormat::Fasta,
            scope: SplicingScopePreset::AllOverlappingAnyStrand,
            origin_mode: RnaReadOriginMode::SingleGene,
            target_gene_ids: vec![],
            roi_seed_capture_enabled: false,
            seed_filter,
            align_config: RnaReadAlignConfig::default(),
            report_id: Some("rna_reads_gene_sheet".to_string()),
            report_mode: RnaReadReportMode::Full,
            checkpoint_path: None,
            checkpoint_every_reads: 10_000,
            resume_from_checkpoint: false,
        },
    )
    .expect("interpret RNA reads");
    let exported_sheet = fasta_dir.path().join("gene_samples.tsv");
    let export_sheet_result = execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsExportSampleSheet {
            path: exported_sheet.display().to_string(),
            seq_id: Some("seq_a".to_string()),
            report_ids: vec!["rna_reads_gene_sheet".to_string()],
            gene_ids: vec!["TP53".to_string()],
            complete_rule: RnaReadGeneSupportCompleteRule::Near,
            append: false,
        },
    )
    .expect("export target-gene RNA-read sample sheet");
    assert_eq!(export_sheet_result.output["report_count"].as_u64(), Some(1));
    assert_eq!(
        export_sheet_result.output["gene_ids"]
            .as_array()
            .map(|values| values.len()),
        Some(1)
    );
    assert_eq!(
        export_sheet_result.output["complete_rule"].as_str(),
        Some("near")
    );
    let sheet_text = fs::read_to_string(exported_sheet).expect("read sample sheet");
    assert!(sheet_text.contains("gene_support_accepted_target_count"));
    assert!(sheet_text.contains("gene_support_exon_pair_support_json"));
    assert!(sheet_text.contains("gene_support_mean_assigned_read_length_bp"));
    assert!(sheet_text.contains("[\"TP53\"]"));
}

#[test]
fn execute_rna_reads_batch_map_writes_bundle_and_sra_plan() {
    let mut state = ProjectState::default();
    state
        .sequences
        .insert("seq_a".to_string(), tp53_isoform_test_sequence());
    let mut engine = GentleEngine::from_state(state);
    let feature_id = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present")
        .features()
        .iter()
        .position(|feature| feature.kind.to_string().eq_ignore_ascii_case("mRNA"))
        .expect("mRNA feature id");
    let dna = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present");
    let read_sequence =
        String::from_utf8(dna.forward_bytes()[98..560].to_vec()).expect("TP53 transcript slice");
    let td = tempdir().expect("tempdir");
    let input_path = td.path().join("sample_a.fa");
    fs::write(&input_path, format!(">tp53_full\n{read_sequence}\n")).expect("write input fasta");
    let manifest_path = td.path().join("samples.tsv");
    fs::write(
        &manifest_path,
        format!(
            "sample_id\tinput_path\tsra_accession\nsample_a\t{}\t\nsample_sra\t\tSRR000001\n",
            input_path.display()
        ),
    )
    .expect("write manifest");
    let out_dir = td.path().join("batch_out");
    let mut seed_filter = RnaReadSeedFilterConfig::default();
    seed_filter.kmer_len = 3;
    seed_filter.min_seed_hit_fraction = 0.0;
    seed_filter.min_weighted_seed_hit_fraction = 0.0;
    seed_filter.min_unique_matched_kmers = 0;
    seed_filter.min_chain_consistency_fraction = 0.0;
    seed_filter.max_median_transcript_gap = 10_000.0;
    seed_filter.min_confirmed_exon_transitions = 0;
    seed_filter.min_transition_support_fraction = 0.0;

    let result = execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsBatchMap {
            manifest_path: manifest_path.display().to_string(),
            seq_id: "seq_a".to_string(),
            seed_feature_id: feature_id,
            gene_ids: vec!["TP53".to_string()],
            out_dir: out_dir.display().to_string(),
            profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
            input_format: RnaReadInputFormat::Fasta,
            scope: SplicingScopePreset::AllOverlappingAnyStrand,
            origin_mode: None,
            target_gene_ids: vec![],
            roi_seed_capture_enabled: false,
            seed_filter,
            align_config: RnaReadAlignConfig {
                band_width_bp: 24,
                min_identity_fraction: 0.60,
                max_secondary_mappings: 5,
            },
            report_mode: RnaReadReportMode::Full,
            align_selection: RnaReadHitSelection::All,
            complete_rule: RnaReadGeneSupportCompleteRule::Near,
            concatemer_settings: RnaReadConcatemerInspectionSettings::default(),
            concatemer_limit: 250,
            continue_on_error: true,
            prepare_sra: false,
            read_cache_dir: None,
            read_work_dir: None,
            drop_intermediate_fastq: false,
        },
    )
    .expect("execute rna-reads batch-map");

    assert!(result.state_changed);
    assert_eq!(
        result.output["schema"].as_str(),
        Some("gentle.rna_read_batch_map_report.v1")
    );
    assert_eq!(result.output["sample_count"].as_u64(), Some(2));
    assert_eq!(result.output["ok_count"].as_u64(), Some(1));
    assert_eq!(result.output["needs_preparation_count"].as_u64(), Some(1));
    assert!(
        result.output["gene_screen_summary_tsv_path"]
            .as_str()
            .is_some_and(|value| value.ends_with("gene_screen_summary.tsv"))
    );
    assert!(engine.get_rna_read_report("rna_batch_sample_a").is_ok());

    let batch_summary = out_dir.join("batch_summary.tsv");
    let gene_screen_summary = out_dir.join("gene_screen_summary.tsv");
    let isoform_support = out_dir.join("isoform_support.tsv");
    let partner_summary = out_dir.join("concatemer_partner_summary.tsv");
    let sample_sheet = out_dir.join("sample_sheet.tsv");
    let sra_plan = out_dir.join("sra_preparation_plan.tsv");
    let batch_json = out_dir.join("batch_report.json");
    for path in [
        &batch_summary,
        &gene_screen_summary,
        &isoform_support,
        &partner_summary,
        &sample_sheet,
        &sra_plan,
        &batch_json,
    ] {
        assert!(path.exists(), "expected '{}' to exist", path.display());
    }
    let summary_text = fs::read_to_string(batch_summary).expect("read batch summary");
    assert!(summary_text.contains("aligned_other_gene_count"));
    assert!(summary_text.contains("all_q90_bp"));
    assert!(summary_text.contains("seed_passed_q99_bp"));
    assert!(summary_text.contains("sample_sra\t"));
    let gene_screen_text =
        fs::read_to_string(gene_screen_summary).expect("read gene-screen summary");
    assert!(gene_screen_text.contains("gentle.rna_read_gene_screen_summary.v1"));
    assert!(gene_screen_text.contains("seed_passed_per_million"));
    assert!(gene_screen_text.contains("accepted_target_per_million"));
    assert!(gene_screen_text.contains("rna_reads_batch_map"));
    let isoform_text = fs::read_to_string(isoform_support).expect("read isoform support");
    assert!(isoform_text.contains("complete_near_count"));
    assert!(isoform_text.contains("TP53"));
    let sample_sheet_text = fs::read_to_string(sample_sheet).expect("read sample sheet");
    assert!(sample_sheet_text.contains("gene_support_accepted_target_count"));
    let sra_plan_text = fs::read_to_string(sra_plan).expect("read SRA plan");
    assert!(sra_plan_text.contains("SRR000001"));
    assert!(sra_plan_text.contains("planned_fasta_path"));
}

#[test]
#[cfg(unix)]
fn execute_reads_acquire_prepare_with_fake_sra_toolkit_reports_outputs() {
    let _env_guard = read_acquisition_test_env_lock()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let td = tempdir().expect("tempdir");
    let bin_dir = td.path().join("fake_sra_toolkit_bin");
    write_fake_sra_toolkit_bin(&bin_dir);
    let previous_path = env::var("PATH").unwrap_or_default();
    let path = if previous_path.is_empty() {
        bin_dir.display().to_string()
    } else {
        format!("{}:{previous_path}", bin_dir.display())
    };
    let _path_guard = EnvVarGuard::set("PATH", &path);

    let manifest_path = td.path().join("reads.tsv");
    fs::write(
        &manifest_path,
        "sample_id\tsra_accession\tread_layout\tanalysis_format\tnote\nsample_a\tSRRFAKE001\tsingle_end\tfasta\tprimary\nsample_dup\tSRRFAKE001\tsingle_end\tfasta\tduplicate\n",
    )
    .expect("write read acquisition manifest");
    let cache_dir = td.path().join("cache");
    let work_dir = td.path().join("work");
    let mut engine = GentleEngine::default();

    let prepare = execute_shell_command(
        &mut engine,
        &ShellCommand::ReadsAcquirePrepare {
            manifest_path: manifest_path.display().to_string(),
            cache_dir: cache_dir.display().to_string(),
            work_dir: work_dir.display().to_string(),
            analysis_format: ReadAcquisitionAnalysisFormat::Fasta,
            read_layout: ReadAcquisitionReadLayout::SingleEnd,
            threads: Some(2),
            max_size: Some("1G".to_string()),
            min_free_gb: None,
            drop_intermediate_fastq: true,
            continue_on_error: false,
        },
    )
    .expect("execute reads acquire prepare with fake SRA Toolkit");

    assert!(!prepare.state_changed);
    let report = &prepare.output["result"]["read_acquisition_report"];
    assert_eq!(
        report["schema"].as_str(),
        Some("gentle.read_acquisition_report.v1")
    );
    assert_eq!(report["sample_count"].as_u64(), Some(2));
    assert_eq!(report["ready_count"].as_u64(), Some(2));
    assert_eq!(report["lifecycle_status"].as_str(), Some("ready"));
    let rows = report["rows"].as_array().expect("read acquisition rows");
    assert_eq!(rows[0]["lifecycle_status"].as_str(), Some("ready"));
    assert_eq!(rows[0]["output_paths"][0]["role"].as_str(), Some("single"));
    assert_eq!(
        rows[0]["output_paths"][0]["analysis_format"].as_str(),
        Some("fasta")
    );
    let fasta_path = rows[0]["output_paths"][0]["path"]
        .as_str()
        .expect("prepared FASTA path");
    assert!(Path::new(fasta_path).exists());
    assert!(!work_dir.join("SRRFAKE001/fastq/SRRFAKE001.fastq").exists());
    let phases: Vec<_> = rows[0]["command_provenance"]
        .as_array()
        .expect("command provenance")
        .iter()
        .filter_map(|entry| entry["phase"].as_str())
        .collect();
    assert_eq!(phases, vec!["prefetch", "validate_sra", "dump_fastq"]);
    assert!(
        rows[1]["warnings"]
            .as_array()
            .expect("duplicate warnings")
            .iter()
            .any(|warning| warning
                .as_str()
                .is_some_and(|text| text.contains("duplicate accession"))),
        "duplicate accession should reuse prepared output"
    );

    let status = execute_shell_command(
        &mut engine,
        &ShellCommand::ReadsAcquireStatus {
            manifest_path: manifest_path.display().to_string(),
            cache_dir: cache_dir.display().to_string(),
            work_dir: work_dir.display().to_string(),
        },
    )
    .expect("execute reads acquire status");
    assert_eq!(
        status.output["result"]["read_acquisition_report"]["ready_count"].as_u64(),
        Some(2)
    );
}

#[test]
#[cfg(unix)]
fn execute_reads_acquire_prepare_can_be_cancelled_from_progress_callback() {
    let _env_guard = read_acquisition_test_env_lock()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let td = tempdir().expect("tempdir");
    let bin_dir = td.path().join("fake_sra_toolkit_bin");
    write_fake_sra_toolkit_bin(&bin_dir);
    let previous_path = env::var("PATH").unwrap_or_default();
    let path = if previous_path.is_empty() {
        bin_dir.display().to_string()
    } else {
        format!("{}:{previous_path}", bin_dir.display())
    };
    let _path_guard = EnvVarGuard::set("PATH", &path);
    let _sleep_guard = EnvVarGuard::set("GENTLE_FAKE_SRA_PREFETCH_SLEEP_SECONDS", "5");

    let manifest_path = td.path().join("reads.tsv");
    fs::write(
        &manifest_path,
        "sample_id\tsra_accession\tread_layout\tanalysis_format\nsample_a\tSRRFAKECANCEL\tsingle_end\tfastq\n",
    )
    .expect("write read acquisition manifest");
    let cache_dir = td.path().join("cache");
    let work_dir = td.path().join("work");
    let mut engine = GentleEngine::default();
    let progress_phases = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let callback_phases = std::sync::Arc::clone(&progress_phases);
    let progress_callback: ShellProgressCallback =
        std::sync::Arc::new(Mutex::new(Box::new(move |progress: OperationProgress| {
            if let OperationProgress::ReadAcquisition(status) = progress {
                callback_phases
                    .lock()
                    .expect("progress phases lock")
                    .push(status.phase.unwrap_or_default());
                return false;
            }
            true
        })));

    let err = execute_shell_command_with_options(
        &mut engine,
        &ShellCommand::ReadsAcquirePrepare {
            manifest_path: manifest_path.display().to_string(),
            cache_dir: cache_dir.display().to_string(),
            work_dir: work_dir.display().to_string(),
            analysis_format: ReadAcquisitionAnalysisFormat::Fastq,
            read_layout: ReadAcquisitionReadLayout::SingleEnd,
            threads: Some(1),
            max_size: None,
            min_free_gb: None,
            drop_intermediate_fastq: false,
            continue_on_error: false,
        },
        &ShellExecutionOptions {
            allow_screenshots: false,
            allow_agent_commands: true,
            progress_callback: Some(progress_callback),
        },
    )
    .expect_err("progress callback should cancel read acquisition");

    assert!(
        err.to_ascii_lowercase().contains("cancel"),
        "expected cancellation error, got {err}"
    );
    assert!(
        progress_phases
            .lock()
            .expect("progress phases lock")
            .iter()
            .any(|phase| phase == "prefetch"),
        "prefetch progress should be emitted before cancellation"
    );
    let inspect = execute_shell_command(
        &mut engine,
        &ShellCommand::ReadsAcquireInspect {
            sra_accession: "SRRFAKECANCEL".to_string(),
            cache_dir: cache_dir.display().to_string(),
            work_dir: work_dir.display().to_string(),
        },
    )
    .expect("inspect cancelled acquisition");
    assert_eq!(
        inspect.output["result"]["read_acquisition_report"]["cancelled_count"].as_u64(),
        Some(1)
    );
    assert_eq!(
        inspect.output["result"]["read_acquisition_report"]["rows"][0]["lifecycle_status"].as_str(),
        Some("cancelled")
    );
    let cancel_again = execute_shell_command(
        &mut engine,
        &ShellCommand::ReadsAcquireCancel {
            sra_accession: "SRRFAKECANCEL".to_string(),
            cache_dir: cache_dir.display().to_string(),
            work_dir: work_dir.display().to_string(),
        },
    )
    .expect("execute cancel command for non-running acquisition");
    assert!(
        cancel_again.output["result"]["read_acquisition_report"]["warnings"]
            .as_array()
            .expect("cancel warnings")
            .iter()
            .any(|warning| warning
                .as_str()
                .is_some_and(|text| text.contains("No running read acquisition"))),
        "cancel command should report when there is nothing active to cancel"
    );
}

#[test]
fn execute_rna_reads_batch_map_shell_and_op_routes_have_parity() {
    let mut state = ProjectState::default();
    state
        .sequences
        .insert("seq_a".to_string(), tp53_isoform_test_sequence());
    let feature_id = state
        .sequences
        .get("seq_a")
        .expect("sequence present")
        .features()
        .iter()
        .position(|feature| feature.kind.to_string().eq_ignore_ascii_case("mRNA"))
        .expect("mRNA feature id");
    let dna = state.sequences.get("seq_a").expect("sequence present");
    let read_sequence =
        String::from_utf8(dna.forward_bytes()[98..560].to_vec()).expect("TP53 transcript slice");
    let td = tempdir().expect("tempdir");
    let input_path = td.path().join("sample_a.fa");
    fs::write(&input_path, format!(">tp53_full\n{read_sequence}\n")).expect("write input fasta");
    let manifest_path = td.path().join("samples.tsv");
    fs::write(
        &manifest_path,
        format!(
            "sample_id\tinput_path\tsra_accession\nsample_a\t{}\t\nsample_sra\t\tSRR000001\n",
            input_path.display()
        ),
    )
    .expect("write manifest");

    let mut seed_filter = RnaReadSeedFilterConfig::default();
    seed_filter.kmer_len = 3;
    seed_filter.min_seed_hit_fraction = 0.0;
    seed_filter.min_weighted_seed_hit_fraction = 0.0;
    seed_filter.min_unique_matched_kmers = 0;
    seed_filter.min_chain_consistency_fraction = 0.0;
    seed_filter.max_median_transcript_gap = 10_000.0;
    seed_filter.min_confirmed_exon_transitions = 0;
    seed_filter.min_transition_support_fraction = 0.0;

    let make_shell_command = |out_dir: &Path| ShellCommand::RnaReadsBatchMap {
        manifest_path: manifest_path.display().to_string(),
        seq_id: "seq_a".to_string(),
        seed_feature_id: feature_id,
        gene_ids: vec!["TP53".to_string()],
        out_dir: out_dir.display().to_string(),
        profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
        input_format: RnaReadInputFormat::Fasta,
        scope: SplicingScopePreset::AllOverlappingAnyStrand,
        origin_mode: None,
        target_gene_ids: vec![],
        roi_seed_capture_enabled: false,
        seed_filter: seed_filter.clone(),
        align_config: RnaReadAlignConfig {
            band_width_bp: 24,
            min_identity_fraction: 0.60,
            max_secondary_mappings: 5,
        },
        report_mode: RnaReadReportMode::Full,
        align_selection: RnaReadHitSelection::All,
        complete_rule: RnaReadGeneSupportCompleteRule::Near,
        concatemer_settings: RnaReadConcatemerInspectionSettings::default(),
        concatemer_limit: 250,
        continue_on_error: true,
        prepare_sra: false,
        read_cache_dir: None,
        read_work_dir: None,
        drop_intermediate_fastq: false,
    };

    let shell_out_dir = td.path().join("shell_batch_out");
    let mut shell_engine = GentleEngine::from_state(state.clone());
    let shell_result =
        execute_shell_command(&mut shell_engine, &make_shell_command(&shell_out_dir))
            .expect("execute rna-reads batch-map via shell route");
    assert!(shell_result.state_changed);

    let op_out_dir = td.path().join("op_batch_out");
    let op = Operation::RunRnaReadBatchMap {
        manifest_path: manifest_path.display().to_string(),
        seq_id: "seq_a".to_string(),
        seed_feature_id: feature_id,
        gene_ids: vec!["TP53".to_string()],
        out_dir: op_out_dir.display().to_string(),
        profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
        input_format: RnaReadInputFormat::Fasta,
        scope: SplicingScopePreset::AllOverlappingAnyStrand,
        origin_mode: None,
        target_gene_ids: vec![],
        roi_seed_capture_enabled: false,
        seed_filter,
        align_config: RnaReadAlignConfig {
            band_width_bp: 24,
            min_identity_fraction: 0.60,
            max_secondary_mappings: 5,
        },
        report_mode: RnaReadReportMode::Full,
        align_selection: RnaReadHitSelection::All,
        complete_rule: RnaReadGeneSupportCompleteRule::Near,
        concatemer_settings: RnaReadConcatemerInspectionSettings::default(),
        concatemer_limit: 250,
        continue_on_error: true,
        prepare_sra: false,
        read_cache_dir: None,
        read_work_dir: None,
        drop_intermediate_fastq: false,
    };
    let op_payload = serde_json::to_string(&op).expect("serialize batch operation");
    let mut op_engine = GentleEngine::from_state(state);
    let op_result = execute_shell_command(
        &mut op_engine,
        &ShellCommand::Op {
            payload: op_payload,
        },
    )
    .expect("execute rna-reads batch-map via serialized op route");
    assert!(op_result.state_changed);

    let op_report = &op_result.output["result"]["rna_read_batch_map_report"];
    assert_eq!(
        shell_result.output["schema"].as_str(),
        Some("gentle.rna_read_batch_map_report.v1")
    );
    assert_eq!(
        op_report["schema"].as_str(),
        Some("gentle.rna_read_batch_map_report.v1")
    );
    for field in [
        "sample_count",
        "ok_count",
        "needs_preparation_count",
        "failed_count",
    ] {
        assert_eq!(
            shell_result.output[field], op_report[field],
            "shell/op batch-map parity mismatch for {field}"
        );
    }
    let shell_statuses: Vec<_> = shell_result.output["rows"]
        .as_array()
        .expect("shell rows")
        .iter()
        .map(|row| row["status"].clone())
        .collect();
    let op_statuses: Vec<_> = op_report["rows"]
        .as_array()
        .expect("op rows")
        .iter()
        .map(|row| row["status"].clone())
        .collect();
    assert_eq!(shell_statuses, op_statuses);
    assert!(
        shell_engine
            .get_rna_read_report("rna_batch_sample_a")
            .is_ok()
    );
    assert!(op_engine.get_rna_read_report("rna_batch_sample_a").is_ok());
    for dir in [&shell_out_dir, &op_out_dir] {
        assert!(dir.join("batch_report.json").exists());
        assert!(dir.join("batch_summary.tsv").exists());
        assert!(dir.join("sra_preparation_plan.tsv").exists());
    }
}

#[test]
fn execute_rna_reads_summarize_gene_support_returns_summary_json_and_writes_file() {
    let mut state = ProjectState::default();
    state
        .sequences
        .insert("seq_a".to_string(), tp53_isoform_test_sequence());
    let mut engine = GentleEngine::from_state(state);
    let feature_id = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present")
        .features()
        .iter()
        .position(|feature| feature.kind.to_string().eq_ignore_ascii_case("mRNA"))
        .expect("mRNA feature id");
    let dna = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present");
    let read_sequence =
        String::from_utf8(dna.forward_bytes()[98..560].to_vec()).expect("TP53 transcript slice");
    let td = tempdir().expect("tempdir");
    let input_path = td.path().join("tp53_gene_support_reads.fa");
    fs::write(&input_path, format!(">tp53_full\n{read_sequence}\n")).expect("write input fasta");
    let mut seed_filter = RnaReadSeedFilterConfig::default();
    seed_filter.kmer_len = 3;
    seed_filter.min_seed_hit_fraction = 0.0;
    seed_filter.min_weighted_seed_hit_fraction = 0.0;
    seed_filter.min_unique_matched_kmers = 0;
    seed_filter.min_chain_consistency_fraction = 0.0;
    seed_filter.max_median_transcript_gap = 10_000.0;
    seed_filter.min_confirmed_exon_transitions = 0;
    seed_filter.min_transition_support_fraction = 0.0;

    execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsInterpret {
            seq_id: "seq_a".to_string(),
            seed_feature_id: feature_id,
            input_path: input_path.display().to_string(),
            profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
            input_format: RnaReadInputFormat::Fasta,
            scope: SplicingScopePreset::AllOverlappingAnyStrand,
            origin_mode: RnaReadOriginMode::SingleGene,
            target_gene_ids: vec![],
            roi_seed_capture_enabled: false,
            seed_filter,
            align_config: RnaReadAlignConfig::default(),
            report_id: Some("tp53_gene_support".to_string()),
            report_mode: RnaReadReportMode::Full,
            checkpoint_path: None,
            checkpoint_every_reads: 10_000,
            resume_from_checkpoint: false,
        },
    )
    .expect("interpret TP53 RNA reads");
    execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsAlignReport {
            report_id: "tp53_gene_support".to_string(),
            selection: RnaReadHitSelection::SeedPassed,
            align_config_override: Some(RnaReadAlignConfig {
                band_width_bp: 24,
                min_identity_fraction: 0.60,
                max_secondary_mappings: 0,
            }),
            selected_record_indices: vec![],
        },
    )
    .expect("align TP53 RNA-read report");
    let source_report = engine
        .get_rna_read_report("tp53_gene_support")
        .expect("read persisted source report");

    let output_path = td.path().join("tp53_gene_support.json");
    let output = execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsSummarizeGeneSupport {
            report_id: "tp53_gene_support".to_string(),
            gene_ids: vec!["TP53".to_string(), "TP73".to_string()],
            selected_record_indices: vec![0],
            complete_rule: RnaReadGeneSupportCompleteRule::Near,
            output_path: Some(output_path.display().to_string()),
        },
    )
    .expect("execute gene-support summary");
    assert!(!output.state_changed);
    assert_eq!(
        output.output["schema"].as_str(),
        Some("gentle.rna_read_gene_support_summary.v1")
    );
    assert_eq!(
        output.output["report_id"].as_str(),
        Some("tp53_gene_support")
    );
    assert!(output.output["generated_at_unix_ms"].as_u64().unwrap_or(0) > 0);
    assert!(output.output["op_id"].as_str().is_some());
    assert!(output.output["run_id"].as_str().is_some());
    assert_eq!(
        output.output["source_report_generated_at_unix_ms"].as_u64(),
        Some(source_report.generated_at_unix_ms as u64)
    );
    assert_eq!(
        output.output["source_report_op_id"].as_str(),
        source_report.op_id.as_deref()
    );
    assert_eq!(
        output.output["source_report_run_id"].as_str(),
        source_report.run_id.as_deref()
    );
    assert_eq!(
        output.output["requested_gene_ids"]
            .as_array()
            .map(|values| values.len()),
        Some(2)
    );
    assert_eq!(output.output["matched_gene_ids"][0].as_str(), Some("TP53"));
    assert_eq!(output.output["missing_gene_ids"][0].as_str(), Some("TP73"));
    assert_eq!(
        output.output["selected_record_indices"][0].as_u64(),
        Some(0)
    );
    assert_eq!(output.output["complete_rule"].as_str(), Some("near"));
    assert_eq!(output.output["accepted_target_count"].as_u64(), Some(1));
    assert_eq!(output.output["complete_count"].as_u64(), Some(1));
    assert_eq!(output.output["all_target"]["read_count"].as_u64(), Some(1));
    assert!(output_path.exists());
    let written = fs::read_to_string(&output_path).expect("read written summary");
    let written_json: serde_json::Value =
        serde_json::from_str(&written).expect("written summary json");
    assert_eq!(written_json, output.output);
}

#[test]
fn execute_rna_reads_inspect_gene_support_returns_audit_json_and_writes_file() {
    let mut state = ProjectState::default();
    state
        .sequences
        .insert("seq_a".to_string(), tp53_isoform_test_sequence());
    let mut engine = GentleEngine::from_state(state);
    let feature_id = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present")
        .features()
        .iter()
        .position(|feature| feature.kind.to_string().eq_ignore_ascii_case("mRNA"))
        .expect("mRNA feature id");
    let dna = engine
        .state()
        .sequences
        .get("seq_a")
        .expect("sequence present");
    let read_sequence =
        String::from_utf8(dna.forward_bytes()[98..560].to_vec()).expect("TP53 transcript slice");
    let td = tempdir().expect("tempdir");
    let input_path = td.path().join("tp53_gene_support_reads.fa");
    fs::write(&input_path, format!(">tp53_full\n{read_sequence}\n")).expect("write input fasta");
    let mut seed_filter = RnaReadSeedFilterConfig::default();
    seed_filter.kmer_len = 3;
    seed_filter.min_seed_hit_fraction = 0.0;
    seed_filter.min_weighted_seed_hit_fraction = 0.0;
    seed_filter.min_unique_matched_kmers = 0;
    seed_filter.min_chain_consistency_fraction = 0.0;
    seed_filter.max_median_transcript_gap = 10_000.0;
    seed_filter.min_confirmed_exon_transitions = 0;
    seed_filter.min_transition_support_fraction = 0.0;

    execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsInterpret {
            seq_id: "seq_a".to_string(),
            seed_feature_id: feature_id,
            input_path: input_path.display().to_string(),
            profile: RnaReadInterpretationProfile::NanoporeCdnaV1,
            input_format: RnaReadInputFormat::Fasta,
            scope: SplicingScopePreset::AllOverlappingAnyStrand,
            origin_mode: RnaReadOriginMode::SingleGene,
            target_gene_ids: vec![],
            roi_seed_capture_enabled: false,
            seed_filter,
            align_config: RnaReadAlignConfig::default(),
            report_id: Some("tp53_gene_support".to_string()),
            report_mode: RnaReadReportMode::Full,
            checkpoint_path: None,
            checkpoint_every_reads: 10_000,
            resume_from_checkpoint: false,
        },
    )
    .expect("interpret TP53 RNA reads");
    execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsAlignReport {
            report_id: "tp53_gene_support".to_string(),
            selection: RnaReadHitSelection::SeedPassed,
            align_config_override: Some(RnaReadAlignConfig {
                band_width_bp: 24,
                min_identity_fraction: 0.60,
                max_secondary_mappings: 0,
            }),
            selected_record_indices: vec![],
        },
    )
    .expect("align TP53 RNA-read report");
    let source_report = engine
        .get_rna_read_report("tp53_gene_support")
        .expect("read persisted source report");

    let output_path = td.path().join("tp53_gene_support_audit.json");
    let output = execute_shell_command(
        &mut engine,
        &ShellCommand::RnaReadsInspectGeneSupport {
            report_id: "tp53_gene_support".to_string(),
            gene_ids: vec!["TP53".to_string(), "TP73".to_string()],
            selected_record_indices: vec![0],
            complete_rule: RnaReadGeneSupportCompleteRule::Near,
            cohort_filter: RnaReadGeneSupportAuditCohortFilter::All,
            output_path: Some(output_path.display().to_string()),
        },
    )
    .expect("execute gene-support audit");
    assert!(!output.state_changed);
    assert_eq!(
        output.output["schema"].as_str(),
        Some("gentle.rna_read_gene_support_audit.v1")
    );
    assert_eq!(
        output.output["report_id"].as_str(),
        Some("tp53_gene_support")
    );
    assert!(output.output["generated_at_unix_ms"].as_u64().unwrap_or(0) > 0);
    assert!(output.output["op_id"].as_str().is_some());
    assert!(output.output["run_id"].as_str().is_some());
    assert_eq!(
        output.output["source_report_generated_at_unix_ms"].as_u64(),
        Some(source_report.generated_at_unix_ms as u64)
    );
    assert_eq!(
        output.output["source_report_op_id"].as_str(),
        source_report.op_id.as_deref()
    );
    assert_eq!(
        output.output["source_report_run_id"].as_str(),
        source_report.run_id.as_deref()
    );
    assert_eq!(
        output.output["requested_gene_ids"]
            .as_array()
            .map(|values| values.len()),
        Some(2)
    );
    assert_eq!(output.output["matched_gene_ids"][0].as_str(), Some("TP53"));
    assert_eq!(output.output["missing_gene_ids"][0].as_str(), Some("TP73"));
    assert_eq!(
        output.output["selected_record_indices"][0].as_u64(),
        Some(0)
    );
    assert_eq!(output.output["complete_rule"].as_str(), Some("near"));
    assert_eq!(output.output["cohort_filter"].as_str(), Some("all"));
    assert_eq!(output.output["evaluated_row_count"].as_u64(), Some(1));
    assert_eq!(output.output["row_count"].as_u64(), Some(1));
    assert_eq!(
        output.output["accepted_target_record_indices"][0].as_u64(),
        Some(0)
    );
    assert_eq!(
        output.output["complete_record_indices"][0].as_u64(),
        Some(0)
    );
    assert_eq!(
        output.output["rows"][0]["status"].as_str(),
        Some("accepted_complete")
    );
    assert_eq!(
        output.output["rows"][0]["status_reason"].as_str(),
        Some("requested_gene_meets_complete_rule")
    );
    assert!(output_path.exists());
    let written = fs::read_to_string(&output_path).expect("read written audit");
    let mut written_json: serde_json::Value =
        serde_json::from_str(&written).expect("written audit json");
    let mut output_json = output.output.clone();
    let written_identity = written_json["rows"][0]["identity_fraction"]
        .as_f64()
        .expect("written identity fraction");
    let output_identity = output_json["rows"][0]["identity_fraction"]
        .as_f64()
        .expect("output identity fraction");
    assert!(
        (written_identity - output_identity).abs() <= 1e-12,
        "written/output identity_fraction drifted more than expected: {written_identity} vs {output_identity}"
    );
    written_json["rows"][0]["identity_fraction"] = serde_json::Value::Null;
    output_json["rows"][0]["identity_fraction"] = serde_json::Value::Null;
    assert_eq!(written_json, output_json);
}

#[test]
fn execute_set_param_updates_display_state() {
    let mut engine = GentleEngine::new();
    let out = execute_shell_command(
        &mut engine,
        &ShellCommand::SetParameter {
            name: "vcf_display_min_qual".to_string(),
            value_json: "33.5".to_string(),
        },
    )
    .expect("execute set-param");
    assert!(out.state_changed);
    assert!(
        (engine.state().display.vcf_display_min_qual - 33.5).abs() < f64::EPSILON,
        "vcf_display_min_qual should be updated by set-param"
    );
}

